UPDATE job
title = #{title}, description = #{description}, location = #{location}, employment_type = #{employmentType}, experience_level = #{experienceLevel}, salary_min = #{salaryMin}, salary_max = #{salaryMax}, status = #{status}, deadline = #{deadline}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id} AND posted_by = #{postedBy}

mapper.select:
SELECT DISTINCT j.* FROM job j

    INNER JOIN job_skill js ON j.id = js.job_id AND js.skill_id IN
    #{sid}


    j.status = 'OPEN'

        AND (j.title LIKE CONCAT('%', #{keyword}, '%')
          OR j.description LIKE CONCAT('%', #{keyword}, '%'))


        AND j.location LIKE CONCAT('%', #{location}, '%')


        AND j.employment_type = #{employmentType}


        AND j.experience_level = #{experienceLevel}


        AND j.salary_min >= #{salaryMin}


        AND j.salary_max <= #{salaryMax}


        AND j.employment_type = 'REMOTE'


        AND j.company_id = #{companyId}


        AND j.posted_at >= DATE_SUB(NOW(), INTERVAL #{postedWithinDays} DAY)


ORDER BY j.posted_at DESC
LIMIT #{size} OFFSET #{offset}

